@startuml
abstract class Directory {
  Directory表示一些扁平(没有子目录)文件的集合，这些文件都只能在创建时写入一次。
  写入之后，就只能读或者删除，不可再修改。
  --
  // 返回目录下所有文件
  + String[] listAll()
  + void deleteFile(String name)
  + long fileLength(String name)
  // 创建一个新文件
  + IndexOutput createOutput(String name, IOContext context)
  // 创建一个临时文件
  + IndexOutput createTempOutput(String prefix, String suffix, IOContext context)
  // 确保对这些文件所有的写入都被转移到稳定的存储介质上去。
  + void sync(Collection<String> names)
  // 重命名文件
  + void rename(String source, String dest)
  // 持久化Directory的元数据
  + void syncMetaData()
  // 打开一个文件
  + IndexInput openInput(String name, IOContext context)
  // 获取锁
  + Lock obtainLock(String name)
}

